import io.jsonwebtoken.Claims;
import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContext;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.GenericFilterBean;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.ServletRequest;
import javax.servlet.ServletResponse;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

public class JwtVerificationFilter extends GenericFilterBean {

    private static final String AUTHORIZATION_HEADER = "Authorization";
    private static final String BEARER_PREFIX = "Bearer ";
    private static final String SECRET_KEY = "secret_key"; // Replace with your secret key

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {
        String authHeader = (String) request.getHeader(AUTHORIZATION_HEADER);
        if (!authHeader.startsWith(BEARER_PREFIX)) {
            chain.doFilter(request, response);
            return;
        }

        try {
            String token = authHeader.replace(BEARER_PREFIX, "");
            Claims claims = Jwts.parser().setSigningKey(SECRET_KEY).parseClaimsJws(token);

            String username = claims.getSubject();
            List<String> authorities = (List<String>) claims.get("authorities");

            UsernamePasswordAuthenticationToken authentication = new UsernamePasswordAuthenticationToken(username, null,
                    authorities.stream().map(authority -> new SimpleGrantedAuthority(authority)).collect(Collectors.toList()));

            SecurityContextHolder.getContext().setAuthentication(authentication);
        } catch (JwtException ex) {
            // Handle token verification exception
        }

        chain.doFilter(request, response);
    }
}